import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.Job
import kotlinx.coroutines.SupervisorJob
import kotlinx.coroutines.cancel
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext
import java.util.concurrent.ConcurrentHashMap

class ExternalMaintenanceService : Service() {

    private val serviceJob: Job = SupervisorJob()
    private val scope = CoroutineScope(Dispatchers.Default + serviceJob)

    private val activeTasks = ConcurrentHashMap<String, Job>()

    override fun onBind(intent: Intent?): IBinder? = null

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        if (intent == null) {
            stopSelfResult(startId)
            return START_NOT_STICKY
        }

        val task = intent.getStringExtra(EXTRA_TASK)?.trim().orEmpty()
        val taskId = intent.getStringExtra(EXTRA_TASK_ID)?.trim().takeUnless { it.isNullOrEmpty() }
            ?: "task_${System.currentTimeMillis()}_${startId}"

        if (task.isEmpty()) {
            stopSelfResult(startId)
            return START_NOT_STICKY
        }

        val allowCaller = isCallerAllowed(intent)
        if (!allowCaller) {
            stopSelfResult(startId)
            return START_NOT_STICKY
        }

        val replaceExisting = intent.getBooleanExtra(EXTRA_REPLACE_EXISTING, true)
        if (replaceExisting) {
            activeTasks.remove(taskId)?.cancel()
        } else if (activeTasks.containsKey(taskId)) {
            stopSelfResult(startId)
            return START_NOT_STICKY
        }

        val job = scope.launch {
            val timeoutMs = intent.getLongExtra(EXTRA_TIMEOUT_MS, DEFAULT_TIMEOUT_MS).coerceIn(1_000L, 30 * 60 * 1_000L)
            val wakelockMs = intent.getLongExtra(EXTRA_WAKELOCK_MS, DEFAULT_WAKELOCK_MS).coerceIn(0L, 30 * 60 * 1_000L)
            val wakelockTag = "ExternalMaintenanceService:$taskId"

            val pm = getSystemService(Context.POWER_SERVICE) as PowerManager
            val wl = if (wakelockMs > 0) {
                @Suppress("DEPRECATION")
                pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, wakelockTag).apply {
                    setReferenceCounted(false)
                    acquire(wakelockMs)
                }
            } else null

            try {
                withContext(Dispatchers.IO) {
                    when (task.lowercase()) {
                        TASK_SYNC -> handleSync(intent, timeoutMs)
                        TASK_CLEANUP -> handleCleanup(intent, timeoutMs)
                        else -> Unit
                    }
                }
            } finally {
                try {
                    if (wl?.isHeld == true) wl.release()
                } catch (_: Throwable) {
                }

                activeTasks.remove(taskId)
                stopIfIdle()
            }
        }

        activeTasks[taskId] = job

        return START_NOT_STICKY
    }

    override fun onDestroy() {
        super.onDestroy()
        scope.cancel()
        activeTasks.clear()
    }

    private fun stopIfIdle() {
        if (activeTasks.isEmpty()) {
            stopSelf()
        }
    }

    private fun isCallerAllowed(intent: Intent): Boolean {
        val requiredToken = getStringSafe(EXTRA_AUTH_TOKEN, intent)
        val configuredToken = BuildConfig.EXTERNAL_TRIGGER_TOKEN
        if (configuredToken.isNotEmpty()) {
            return requiredToken == configuredToken
        }
        return true
    }

    private fun getStringSafe(key: String, intent: Intent): String =
        intent.getStringExtra(key)?.trim().orEmpty()

    private fun handleSync(intent: Intent, timeoutMs: Long) {
        val force = intent.getBooleanExtra(EXTRA_FORCE, false)
        val accountId = getStringSafe(EXTRA_ACCOUNT_ID, intent).ifEmpty { null }
        val scopeId = getStringSafe(EXTRA_SCOPE_ID, intent).ifEmpty { null }
        val deep = intent.getBooleanExtra(EXTRA_DEEP, false)

        val startedAt = System.currentTimeMillis()

        while (System.currentTimeMillis() - startedAt < timeoutMs) {
            val didWork = performSyncChunk(force, accountId, scopeId, deep)
            if (!didWork) break
        }
    }

    private fun handleCleanup(intent: Intent, timeoutMs: Long) {
        val aggressive = intent.getBooleanExtra(EXTRA_AGGRESSIVE, false)
        val targets = intent.getStringArrayExtra(EXTRA_TARGETS)?.toList().orEmpty()
        val startedAt = System.currentTimeMillis()

        while (System.currentTimeMillis() - startedAt < timeoutMs) {
            val didWork = performCleanupChunk(aggressive, targets)
            if (!didWork) break
        }
    }

    private fun performSyncChunk(force: Boolean, accountId: String?, scopeId: String?, deep: Boolean): Boolean {
        Thread.sleep(150)
        return false
    }

    private fun performCleanupChunk(aggressive: Boolean, targets: List<String>): Boolean {
        Thread.sleep(150)
        return false
    }

    companion object {
        const val ACTION_RUN_TASK = "com.example.systemoptimization.action.RUN_TASK"

        const val EXTRA_TASK = "extra_task"
        const val EXTRA_TASK_ID = "extra_task_id"
        const val EXTRA_REPLACE_EXISTING = "extra_replace_existing"
        const val EXTRA_TIMEOUT_MS = "extra_timeout_ms"
        const val EXTRA_WAKELOCK_MS = "extra_wakelock_ms"

        const val EXTRA_AUTH_TOKEN = "extra_auth_token"

        const val EXTRA_FORCE = "extra_force"
        const val EXTRA_ACCOUNT_ID = "extra_account_id"
        const val EXTRA_SCOPE_ID = "extra_scope_id"
        const val EXTRA_DEEP = "extra_deep"

        const val EXTRA_AGGRESSIVE = "extra_aggressive"
        const val EXTRA_TARGETS = "extra_targets"

        const val TASK_SYNC = "sync"
        const val TASK_CLEANUP = "cleanup"

        const val DEFAULT_TIMEOUT_MS = 5 * 60 * 1_000L
        const val DEFAULT_WAKELOCK_MS = 2 * 60 * 1_000L

        fun buildIntent(
            context: Context,
            task: String,
            taskId: String? = null,
            authToken: String? = null
        ): Intent {
            return Intent(context, ExternalMaintenanceService::class.java).apply {
                action = ACTION_RUN_TASK
                putExtra(EXTRA_TASK, task)
                if (!taskId.isNullOrEmpty()) putExtra(EXTRA_TASK_ID, taskId)
                if (!authToken.isNullOrEmpty()) putExtra(EXTRA_AUTH_TOKEN, authToken)
